<?php declare(strict_types=1);namespace App\Services;final class ProfileRecommendationService{public function recommend(array $profile,array $health):?string{if(($health['status']??'healthy')==='healthy')return null;$order=['ultra','high','standard','micro'];$current=array_search($profile['name']??'standard',$order,true);return $current===false||$current===count($order)-1?null:$order[$current+1];}}
